    throw createClientRequestError('Gemini requiere API key configurada en Integraciones IA.', 400);
  }
  if (typeof fetch !== 'function') {
    throw new Error('No hay soporte fetch en este runtime para Gemini.');
  }
  const selectedModel = normalizeChatAgentModel('gemini-cli', model);
  const endpoint = `${defaultGeminiApiBaseUrl}/models/${encodeURIComponent(selectedModel)}:generateContent?key=${encodeURIComponent(
    safeApiKey
  )}`;
  const body = {
    contents: [
      {
        role: 'user',
        parts: [
          {
            text: buildGeminiPromptWithReasoning(prompt, reasoningEffort)
          }
        ]
      }
    ]
  };
  if (chatMaxOutputTokens) {
    body.generationConfig = {
      maxOutputTokens: chatMaxOutputTokens
    };
  }

  let response;
  try {
    response = await fetch(endpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify(body)
