  if (!response.ok) {
    const reason =
      truncateForNotify(extractGeminiErrorMessage(payload) || `HTTP ${response.status}`, 260) ||
      `HTTP ${response.status}`;
    const safeStatusCode =
      response.status >= 400 && response.status < 500 ? response.status : 502;
    throw createClientRequestError(`Gemini devolvió error: ${reason}`, safeStatusCode);
  }

  const text = extractGeminiAssistantText(payload);
  if (!text) {
    const reason = truncateForNotify(extractGeminiErrorMessage(payload) || 'Gemini sin contenido', 240);
